use ordered_float::OrderedFloat;
use rayon::prelude::*;
use std::cmp::Reverse;
use std::collections::BinaryHeap;
use std::sync::RwLock;

struct InnerDB {
    ids: Vec<u64>,
    vectors: Vec<[f32; 128]>,
}

pub struct VectorDB {
    inner: RwLock<InnerDB>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            inner: RwLock::new(InnerDB {
                ids: Vec::new(),
                vectors: Vec::new(),
            }),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        let mut inner = self.inner.write().unwrap();
        // Convert vector to array of size 128
        let arr: [f32; 128] = vector.try_into().expect("Vector length must be 128");
        inner.ids.push(id);
        inner.vectors.push(arr);
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut inner = self.inner.write().unwrap();
        let start_len = inner.ids.len();
        for (id, vec) in vectors {
            let arr: [f32; 128] = vec.try_into().expect("Vector length must be 128");
            inner.ids.push(id);
            inner.vectors.push(arr);
        }
        inner.ids.len() - start_len
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let inner = self.inner.read().unwrap();
        let query_arr: &[f32; 128] = vector.try_into().expect("Vector length must be 128");
        let k = top_k as usize;

        // Use parallel iterator over vectors and ids
        let heap = inner
            .vectors
            .par_iter()
            .zip(&inner.ids)
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap, (db_vec, &id)| {
                    let dist_sq = squared_distance(query_arr, db_vec);
                    heap.push(Reverse((OrderedFloat(dist_sq), id)));
                    if heap.len() > k {
                        heap.pop();
                    }
                    heap
                },
            )
            .reduce(
                || BinaryHeap::with_capacity(0),
                |mut heap1, heap2| {
                    for Reverse((dist, id)) in heap2 {
                        heap1.push(Reverse((dist, id)));
                        if heap1.len() > k {
                            heap1.pop();
                        }
                    }
                    heap1
                },
            );

        // Extract results sorted by distance ascending
        let mut results: Vec<_> = heap
            .into_sorted_vec()
            .into_iter()
            .map(|Reverse((OrderedFloat(dist_sq), id))| {
                let distance = dist_sq.sqrt();
                SearchResult { id, distance }
            })
            .collect();
        // into_sorted_vec returns ascending (Reverse order)
        results.reverse();
        results
    }
}

fn squared_distance(a: &[f32; 128], b: &[f32; 128]) -> f64 {
    let mut sum = 0.0f64;
    for i in 0..128 {
        let diff = a[i] as f64 - b[i] as f64;
        sum += diff * diff;
    }
    sum
}"}

